import React, { useState } from 'react';
import axios from 'axios';

const API_BASE = process.env.REACT_APP_BACKEND_URL || 'http://localhost:4000';

export default function Login({ onLogin }) {
  const [email, setEmail] = useState('test@example.com');
  const [password, setPassword] = useState('password123');
  const [name, setName] = useState('');
  const [role, setRole] = useState('client');
  const [isRegister, setIsRegister] = useState(false);
  const [loading, setLoading] = useState(false);

  const submit = async () => {
    if (loading) return;
    setLoading(true);
    try {
      if (isRegister) {
        await axios.post(`${API_BASE}/api/auth/register`, { name, email, password, role });
      }

      const res = await axios.post(`${API_BASE}/api/auth/login`, { email, password });
      if (res.data.ok) {
        const user = res.data.user;
        onLogin(user);
        localStorage.setItem('token', res.data.token);
      } else {
        alert('Credenciales invalidas');
      }
    } catch (err) {
      const message = err.response?.data?.error || 'Error al procesar la solicitud';
      alert(message);
    } finally {
      setLoading(false);
    }
  };

  const toggleMode = () => {
    setIsRegister((value) => !value);
  };

  return (
    <div style={{ padding: 20, maxWidth: 320 }}>
      <h3>{isRegister ? 'Crear Cuenta' : 'Login'}</h3>
      {isRegister && (
        <>
          <input
            placeholder="Nombre"
            value={name}
            onChange={(e) => setName(e.target.value)}
            style={{ width: '100%', marginBottom: 8 }}
          />
          <select value={role} onChange={(e) => setRole(e.target.value)} style={{ width: '100%', marginBottom: 8 }}>
            <option value="client">Cliente</option>
            <option value="agent">Agente</option>
            <option value="admin">Administrador</option>
          </select>
        </>
      )}
      <input
        placeholder="Email"
        value={email}
        onChange={(e) => setEmail(e.target.value)}
        style={{ width: '100%', marginBottom: 8 }}
      />
      <input
        placeholder="Contraseña"
        type="password"
        value={password}
        onChange={(e) => setPassword(e.target.value)}
        style={{ width: '100%', marginBottom: 8 }}
      />
      <button onClick={submit} disabled={loading} style={{ width: '100%', marginBottom: 8 }}>
        {loading ? 'Procesando...' : isRegister ? 'Registrar y entrar' : 'Entrar'}
      </button>
      <button type="button" onClick={toggleMode} style={{ width: '100%' }}>
        {isRegister ? 'Ya tengo cuenta' : 'Crear una cuenta nueva'}
      </button>
    </div>
  );
}
